327	        %div_by_1 = assume div_by<32>, %int_tile : tile<8xi16>
328	
329	        // Assume that every 4th element (starting with element 0) along
330	        // dimension 0 is divisible by 32 that and all integers are
331	        // montonically increasing by 1 within each group of 4.
332	        %int_tile_2 = constant <i16: [96, 97, 98, 99, 64, 65, 66, 67]> : tile<8xi16>
333	        %div_by_2 = assume div_by<32, every 4 along 0>, %int_tile_2 : tile<8xi16>
334	
335	        // Assume that every rectangular chunk of size [1, 4, 2] has the same
336	        // values.
337	        # %input_rank3 = reshape %input : tile<ptr<f32>> -> tile<1x1x1xptr<f32>>
338	        # %ptr_3d = broadcast %input_rank3 : tile<1x1x1xptr<f32>> -> tile<1x8x8xptr<f32>>
339	        %same_elem = assume same_elements<[1, 4, 2]>, %ptr_3d : tile<1x8x8xptr<f32>>
340	
341	        // Assume that every value is greater or equal to 5.
342	        %int_tile_3 = constant <i16: [5, 9, 10, 11, 6, 5, 5, 7]> : tile<8xi16>
343	        %bounded = assume bounded<5, ?>, %int_tile_3 : tile<8xi16>
344	      # }
345	    # }
346	  }]];
