                       CudaTileArg<UnitAttr, flush_to_zero_desc, "13.1">:$flush_to_zero);

  let results = (outs CudaTileArg<CudaTile_BaseFloatTileType, "The result of the :code:`divf` operation.", "13.1">:$result);

